	font-family: "Plus Jakarta Sans", Inter, sans-serif;
	font-size: 16px;
	line-height: 1.5;
	letter-spacing: -0.32px;
	color: #585858;
}

.phoneStage {
	position: relative;
	overflow: hidden;
	border-radius: 12px;
	background:
		radial-gradient(circle at 50% -35%, #50a8e4 0 25%, transparent 55%),
		radial-gradient(circle at 50% 125%, #50a8e4 0 22%, transparent 52%), #fff;
	min-height: 349px;
}

.phone {
	position: absolute;
	left: 50%;
	top: 40px;
	transform: translateX(-50%);
	width: 176px;
	height: 378px;
	border-radius: 32px;
	background: #262424;
	padding: 28px 14px;
	box-shadow: 0 24px 60px rgba(0, 0, 0, 0.16);
}

.speaker {
	position: absolute;
	top: 12px;
	left: 50%;
	transform: translateX(-50%);
	width: 48px;
	height: 5px;
	border-radius: 99px;
	background: rgba(255, 255, 255, 0.28);
}

.phoneHeader {
	height: 64px;
	border-radius: 18px;
	background: #a0f4d8;
	margin-bottom: 16px;
}

.phone span {
	display: block;
	padding: 12px;
	border-radius: 14px;
	background: #fff;
	color: #262424;
	font-size: 12px;
	margin-bottom: 10px;
}

.storeA,
.storeB {
	position: absolute;
	display: inline-flex;
	align-items: center;
	justify-content: center;
	height: 29px;
	padding: 0 14px;
	border-radius: 29px;
	background: #262424;
	color: #fff;
	font-size: 10px;
	letter-spacing: 0.5px;
}

.storeA {
	right: 28px;
	top: 51px;
}
.storeB {
	left: 32px;
	top: 112px;
}

