	.section {
		padding: 64px 24px;
	}
	.header h2 {
		font-size: 48px;
		letter-spacing: -1.92px;
	}
	.steps {
		grid-template-columns: 1fr;
		width: 100%;
	}
	.featured {
		grid-row: auto;
		grid-template-columns: minmax(0, 1fr) minmax(var(--size-feature-min), 0.8fr);
	}
	.phoneStage {
		min-height: 320px;
	}
	.phone {
		top: var(--space-lg);
	}
}

@media (max-width: 767px) {
	.section {
		padding: 48px 16px;
		gap: 48px;
	}
	.header h2 {
		font-size: 40px;
		letter-spacing: -1.6px;
	}
	.steps {
		padding: var(--space-2xs);
	}
	.featured {
		grid-template-columns: 1fr;
		min-height: auto;
	}
	.stepCard {
		min-height: 0;
		gap: var(--space-lg);
		padding: var(--space-sm);
	}
	.stepCopy h3 {
		font-size: var(--font-card-tablet);
	}
	.stepCopy p {
		font-size: var(--font-body-min);
	}
	.phoneStage {
		min-height: 300px;
	}
	.phone {
		width: var(--size-phone-tablet-w);
		height: var(--size-phone-tablet-h);
		padding: var(--space-md) var(--space-xs);
	}
	.storeA,
	.storeB {
		min-height: var(--touch-target);
	}
}

@media (max-width: 479px) {
	.section {
		padding: var(--space-xl) var(--space-sm);
		gap: var(--space-lg);
	}
	.header h2 {
		font-size: var(--space-lg);
		letter-spacing: -1.28px;
	}
	.steps {
		border-radius: var(--space-sm);
	}
	.stepCard {
		border-radius: var(--radius-md);
	}
	.stepCopy h3 {
		font-size: var(--font-card-compact);
	}
	.phoneStage {
		min-height: 280px;
	}
	.phone {
		width: var(--size-phone-mobile-w);
		height: var(--size-phone-mobile-h);
	}
	.storeA {
		right: var(--space-xs);
	}
	.storeB {
		left: var(--space-xs);
	}
}

